  ('aboriginal-6e11b43e-moex-00036', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律之敘述，下列何者錯誤？', '["所謂法律，原則上係對不特定人之權利義務所為之抽象規定", "預算案實質上為行政行為之一種，但因具有法律之形式，故稱之為措施性法律", "若法律實際適用結果，僅單一或少數對象受該法律規範者，即為憲法所不許", "法律明確性原則並無禁止立法者衡酌生活事實之複雜性及適用於個案之妥當性，適當運用不確 定法律概念之可能性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6e11b43e-moex-00037', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於法律不溯及既往原則之敘述，下列何者錯誤？', '["不論負擔性或授益性法律均有法律不溯及既往之適用", "真正溯及既往係指，法規於時間上向前適用於已確定終結之案件", "原則上法律不溯及既往只禁止真正溯及既往之情形，惟若不真正溯及既往之影響過鉅，則宜制 定過渡條款", "基於重大公益之考量仍可能例外允許制定真正溯及既往之法規"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
