  ('aboriginal-6e11b43e-moex-00041', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-114-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於行政機關管轄權限之變更，下列敘述何者正確？', '["行政機關依法規委任所屬下級機關執行事務，不需要公告及刊登政府公報或新聞紙", "除有法律明文規定，否則行政機關不得將其權限之一部委託民間團體辦理", "行政機關得僅依行政程序法第15條第2項規定，將其權限委託不相隸屬之行政機關", "行政機關依法規將其權限之一部分，委託民間團體辦理，該民間團體於委託範圍內，視為行政 機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:10+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL)
